import numpy as np


class Stats:
    def __init__(self, dtype=np.int):  # BUG: np.int removed since numpy 1.20
        self.dtype = dtype

    def compute(self, arr):
        out = arr.astype(self.dtype)
        return out.mean(), out.std()


def compute(arr):
    s = Stats()
    return s.compute(arr)


def main():
    np.random.seed(0)
    arr = np.random.rand(100) * 10
    result = compute(arr)
    print(result)


if __name__ == '__main__':
    main()
